function waystoneEntry(id,cat,affix,zhPattern,icon='路',zhLabel=null,enPattern=null,vars=null){const side=affix==='prefix'?'前缀':affix==='suffix'?'后缀':'词缀';const label=zhLabel||`${side} · ${zhPattern.replace(/\n/g,' / ')}`;return {id:`ws_${id}`,cat,zh:label,en:label,zhPattern,enPattern:enPattern||zhPattern,icon,affix,vars:vars||[]}}
function waystoneRangeGroup(prefix,cat,affix,template,ranges,icon='路'){return ranges.map((r,i)=>waystoneEntry(`${prefix}_${i+1}`,cat,affix,template.replace('{r}',`(${r[0]}—${r[1]})`),icon,null,null,null))}
function makeWaystoneMods(){const out=[];const add=x=>out.push(x);add(waystoneEntry('reward_prefix','收益','prefix','魔法和稀有怪物总增 25%','益','前缀 · 魔法和稀有怪物 / 怪物词缀奖励'));add(waystoneEntry('rare_extra_affix','危险','suffix','稀有怪物额外具有 1 个词缀','稀'));
for(const [key,el,icon] of [['fire','火焰','火'],['cold','冰霜','冰'],['lightning','闪电','电'],['chaos','混沌','混']])for(const e of waystoneRangeGroup(`extra_${key}`,'元素伤害','prefix',`怪物造成相当于伤害 {r}% 的额外${el}伤害`,[[5,9],[10,14],[15,19],[20,24]],icon))add(e);
for(const e of waystoneRangeGroup('monster_damage','怪物强化','prefix','怪物伤害提高 {r}%',[[5,9],[10,14],[15,19],[20,24]],'伤'))add(e);for(let i=0;i<2;i++)add(waystoneEntry(`monster_speed_${i+1}`,'怪物强化','prefix','怪物的攻击，施法，移动速度提高 (10—15)%','速',`前缀 · 怪物攻击/施法/移动速度提高（版本 ${i+1}）`));
[[80,120,11,15],[140,180,16,20],[200,240,21,25],[260,300,26,30]].forEach((r,i)=>add(waystoneEntry(`monster_crit_${i+1}`,'怪物强化','prefix','怪物暴击率提高 {v1}%\n+{v2}% 怪物暴击伤害加成','暴',null,null,[{key:'v1',label:'暴击率',sourceMin:r[0],sourceMax:r[1]},{key:'v2',label:'暴击伤害加成',sourceMin:r[2],sourceMax:r[3]}])));
for(const e of waystoneRangeGroup('monster_life','怪物强化','prefix','怪物生命总增 {r}%',[[10,14],[15,19],[20,25],[26,30]],'生'))add(e);for(const e of waystoneRangeGroup('monster_ele_res','怪物防御','suffix','+{r}% 怪物的元素抗性',[[20,24],[25,29],[30,34],[35,40]],'抗'))add(e);add(waystoneEntry('monster_armour','怪物防御','suffix','怪物具有护甲','甲'));add(waystoneEntry('monster_evasion','怪物防御','suffix','怪物具有闪避','闪'));add(waystoneEntry('monster_es_as_life','怪物防御','suffix','怪物将生命上限的 (12—25)% 转化为额外能量护盾上限','盾'));
for(const e of waystoneRangeGroup('poison','异常状态','prefix','怪物的击中有 {r}% 的几率造成中毒',[[13,19],[20,26],[27,33],[34,40]],'毒'))add(e);for(const e of waystoneRangeGroup('bleed','异常状态','prefix','怪物的击中有 {r}% 的几率造成流血',[[5,10],[10,15],[15,20],[20,25]],'血'))add(e);
[[30,39,30,39],[50,59,40,49],[70,79,60,69],[70,79,70,79]].forEach((r,i)=>add(waystoneEntry(`ailment_stun_threshold_${i+1}`,'怪物防御','suffix','怪物的异常状态阈值提高 {v1}%\n怪物的晕眩阈值提高 {v2}%','阈',null,null,[{key:'v1',label:'异常状态阈值',sourceMin:r[0],sourceMax:r[1]},{key:'v2',label:'晕眩阈值',sourceMin:r[2],sourceMax:r[3]}])));
for(const e of waystoneRangeGroup('armour_break','怪物强化','prefix','怪物粉碎护甲，相当于造成物理伤害的 {r}%',[[15,20],[20,25],[25,30],[30,45]],'破'))add(e);for(const e of waystoneRangeGroup('accuracy','怪物强化','prefix','怪物的命中值提高 {r}%',[[10,20],[20,30],[30,40],[40,50]],'准'))add(e);for(const e of waystoneRangeGroup('stun_buildup','怪物强化','prefix','怪物的晕眩积蓄提高 {r}%',[[50,60],[70,80],[90,100],[100,110]],'晕'))add(e);
for(const e of waystoneRangeGroup('elemental_ailment_app','异常状态','suffix','怪物的元素异常状态应用提高 {r}%',[[60,79],[80,99],[100,119],[120,130]],'异'))add(e);[2,3].forEach(n=>add(waystoneEntry(`extra_projectiles_${n}`,'投射物','prefix',`怪物可以发射 ${n} 个额外投射物`,'投')));add(waystoneEntry('monster_aoe','怪物强化','suffix','怪物效果区域的提高 50%','域'));
['衰弱','时空锁链','元素要害'].forEach((name,i)=>add(waystoneEntry(`player_curse_${i+1}`,'诅咒','suffix',`玩家周期性受到${name}诅咒`,'咒')));['点燃地面','冰缓地面','感电地面'].forEach((name,gi)=>{for(let i=0;i<4;i++)add(waystoneEntry(`ground_${gi+1}_${i+1}`,'地面效果','suffix',`区域内有${name}`,gi===0?'火':gi===1?'冰':'电',`后缀 · 区域内有${name}（密度 ${i+1}）`))});
for(const e of waystoneRangeGroup('minion_pen','召唤生物','prefix','召唤生物的伤害穿透 {r}% 元素抗性',[[6,8],[9,11],[12,14],[14,16]],'召'))add(e);for(const e of waystoneRangeGroup('player_max_res','玩家削弱','suffix','玩家的抗性上限 {r}%',[[-4,-3],[-6,-4],[-8,-6],[-10,-8]],'抗'))add(e);for(const e of waystoneRangeGroup('flask_charge','玩家削弱','suffix','玩家获得的药剂充能降低 {r}%',[[20,24],[25,29],[30,35]],'药'))add(e);for(const e of waystoneRangeGroup('life_es_recovery','玩家削弱','suffix','玩家的生命和能量护盾总回复速度总降 {r}%',[[20,29],[30,35],[36,40],[36,40]],'回'))add(e);for(const e of waystoneRangeGroup('cooldown_recovery','玩家削弱','suffix','玩家的冷却回复率总降 {r}%',[[15,20],[20,25],[25,30],[25,30]],'冷'))add(e);for(const e of waystoneRangeGroup('reduced_crit_taken','怪物防御','suffix','怪物受到的暴击伤害降低 {r}%',[[15,19],[20,25],[26,30]],'暴'))add(e);for(const e of waystoneRangeGroup('curse_effect_less','诅咒','suffix','怪物受到的诅咒效果总降 {r}%',[[20,30],[30,40],[40,50],[40,50]],'咒'))add(e);
return out}
const WAYSTONE_MOD_DB=makeWaystoneMods();
function catalogSearchText(x){return [x.zh,x.en,x.zhPattern,x.enPattern,x.cat,x.affix].filter(Boolean).join(' ').toLowerCase()}
function catalogTemplateEntry(x){const e={id:x.id,name:currentLabel(x),text:currentPattern(x)};if(x.vars&&x.vars.length)e.vars=clone(x.vars);return e}
function hasCatalogVariables(x){const raw=currentPattern(x)||'';return !!((x.vars&&x.vars.length)||/\{v\d+\}|\(-?\d+\s*[—–-]+\s*-?\d+\)/.test(raw))}
function catalogKey(x){return hasCatalogVariables(x)?`tablet:waystone:${x.id||currentLabel(x)||currentPattern(x)}`:`simple:${state.scope}:${x.id}:${state.locale}`}
function addCatalogCondition(x){const raw=currentPattern(x);if(hasCatalogVariables(x))return addTablet(catalogTemplateEntry(x),'waystone',state.mode);return addSimple(currentLabel(x),x.advanced?raw:flexText(raw),state.mode,catalogKey(x),!!x.advanced)}
