const state={scope:'equipment',locale:'zh',mode:'must',category:'全部',search:'',affix:'全部词缀',sort:'source',tabletView:'mods',must:[],any:[],exclude:[],limit:250,history:[]};
const $=s=>document.querySelector(s), $$=s=>[...document.querySelectorAll(s)];
const clone=x=>JSON.parse(JSON.stringify(x));
const uid=()=>Math.random().toString(36).slice(2)+Date.now().toString(36).slice(-5);
function escapeHtml(s){return String(s).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));}
function escapeRegex(s){return String(s).replace(/[.*+?^${}()|[\]\\]/g,'\\$&');}
function flexText(s){return escapeRegex(s).replace(/\\ /g,'\\s*').replace(/，/g,'[,，]?').replace(/：/g,'[:：]?').replace(/—/g,'[—–-]');}
function toast(msg){const n=$('#toast');n.textContent=msg;n.classList.add('show');clearTimeout(toast.t);toast.t=setTimeout(()=>n.classList.remove('show'),1600);}
function pushHistory(){state.history.push(clone({scope:state.scope,locale:state.locale,must:state.must,any:state.any,exclude:state.exclude}));if(state.history.length>40)state.history.shift();}
function undo(){const h=state.history.pop();if(!h)return toast('没有可撤销操作');Object.assign(state,h);syncControls();renderAll();}
function safeRegex(pattern){try{return new RegExp(pattern,'im')}catch{return null}}
function trieRegex(values){const root={};for(const raw of values.map(String)){let n=root;for(const ch of raw)n=n[ch]||(n[ch]={});n.$=1}function comp(n){const groups={},alts=[];for(const [ch,child] of Object.entries(n)){if(ch==='$')continue;const suf=comp(child);(groups[suf]||(groups[suf]=[])).push(ch)}for(const [suf,chs] of Object.entries(groups)){let head;if(chs.length===1)head=escapeRegex(chs[0]);else if(chs.every(x=>/\d/.test(x))){const ds=chs.map(Number).sort((a,b)=>a-b);const seq=ds.every((x,i)=>i===0||x===ds[i-1]+1);head=seq?`[${ds[0]}-${ds.at(-1)}]`:`[${ds.join('')}]`}else head=`(?:${chs.map(escapeRegex).join('|')})`;alts.push(head+suf)}if(n.$)alts.push('');return alts.length===1?alts[0]:`(?:${alts.join('|')})`}return comp(root)}
function numberPattern(min,max,sourceMin=null,sourceMax=null){min=min===''||min==null||Number.isNaN(+min)?null:Math.trunc(+min);max=max===''||max==null||Number.isNaN(+max)?null:Math.trunc(+max);if(min==null&&max==null)return '-?\\d+';if(min==null)min=(sourceMin!=null&&sourceMin<=max)?sourceMin:Math.min(-999,max);if(max==null)max=(sourceMax!=null&&sourceMax>=min)?sourceMax:Math.max(999,min);if(min>max)[min,max]=[max,min];if(max-min>2400)return '-?\\d+';const vals=[];for(let i=min;i<=max;i++)vals.push(i);return trieRegex(vals)}
function parseTemplate(entry){if(entry._parsed)return entry._parsed;let text=entry.text,vars=entry.vars?clone(entry.vars):[],parts=[],last=0,idx=0,m;const re=/\((-?\d+)\s*[—–-]+\s*(-?\d+)\)/g;while((m=re.exec(text))){parts.push({t:'text',v:text.slice(last,m.index)});const key='v'+(++idx);parts.push({t:'var',key});vars.push({key,label:'数值 '+idx,sourceMin:+m[1],sourceMax:+m[2]});last=re.lastIndex}parts.push({t:'text',v:text.slice(last)});if(entry.vars&&entry.vars.length){parts=[];last=0;const vr=/\{(v\d+)\}/g;while((m=vr.exec(text))){parts.push({t:'text',v:text.slice(last,m.index)});parts.push({t:'var',key:m[1]});last=vr.lastIndex}parts.push({t:'text',v:text.slice(last)})}return entry._parsed={parts,vars}}
function tabletPattern(c,identify=false){const parsed=parseTemplate(c.entry),vals=c.values||{};let out='';for(const p of parsed.parts){if(p.t==='text')out+=flexText(p.v).replace(/\\\n/g,'[\\s\\S]{0,180}?');else{const meta=parsed.vars.find(x=>x.key===p.key)||{},user=vals[p.key]||{};out+=`(?:${numberPattern(identify?'':user.min,identify?'':user.max,meta.sourceMin,meta.sourceMax)})(?:\\s*\\([^\\n)]*\\))?`}}return out}
function conditionPattern(c){if(c.kind==='tablet')return tabletPattern(c);return c.pattern}
function addSimple(label,pattern,mode=state.mode,key=pattern,advanced=false){if(state[mode].some(x=>x.key===key))return toast('该条件已存在');pushHistory();state[mode].push({id:uid(),key,kind:'simple',label,pattern,advanced});renderAll()}
function addTablet(entry,kind='mod',mode=state.mode){if(!entry)return;const key=`tablet:${kind}:${entry.id||entry.name||entry.text}`;if(state[mode].some(x=>x.key===key))return toast('该条件已存在');pushHistory();const values={};for(const v of parseTemplate(entry).vars)values[v.key]=kind==='waystone'&&v.sourceMin!=null?{min:String(v.sourceMin),max:String(v.sourceMax)}:{min:'',max:''};state[mode].push({id:uid(),key,kind:'tablet',label:entry.name||entry.text.split('\n')[0],entry:clone(entry),values});renderAll()}
function removeCondition(mode,id){pushHistory();state[mode]=state[mode].filter(x=>x.id!==id);renderAll()}
function outputString(){const must=state.must.map(c=>`"${conditionPattern(c)}"`).join(' ');const any=state.any.length?`"(?:${state.any.map(conditionPattern).join('|')})"`:'';const ex=state.exclude.map(c=>`!"${conditionPattern(c)}"`).join(' ');return [must,any,ex].filter(Boolean).join(' ')}
function currentSimpleDB(){return state.scope==='waystone'?[...WAYSTONE_MOD_DB,...(GENERAL_DB.waystone||[])]:GENERAL_DB[state.scope]||[]}
function currentLabel(x){return state.locale==='zh'?x.zh:x.en}
function currentPattern(x){return state.locale==='zh'?x.zhPattern:x.enPattern}
function renderCatalog(){const tablet=state.scope==='tablet';$('#tabletViews').classList.toggle('hidden',!tablet);$('#affixFilter').classList.toggle('hidden',!tablet||state.tabletView!=='mods');$('#sort').classList.toggle('hidden',!tablet||state.tabletView!=='mods');$('#localeNote').style.display=tablet?'block':'none';$('#catalogTitle').textContent={equipment:'装备词条',waystone:'引路石词条',tablet:'石板完整词条库',stash:'仓库通用',advanced:'高级正则片段'}[state.scope];$('#catalogSub').textContent=tablet?`${TABLET_DB.mods.length} 条普通词缀 · ${TABLET_DB.uniques.length} 件传奇 · ${TABLET_DB.bases.length} 种基底`:state.scope==='waystone'?`${WAYSTONE_MOD_DB.length} 条编年史引路石词条/T级 + ${(GENERAL_DB.waystone||[]).length} 条常用基础属性；有浮动数值的快捷项可填写最小/最大，固定词条不显示输入框`:'点击词条加入当前条件组';if(tablet){renderTabletCatalog()}else{renderSimpleCatalog()}}
function renderSimpleCatalog(){const db=currentSimpleDB();const cats=['全部',...new Set(db.map(x=>x.cat))];$('#chips').innerHTML=cats.map(c=>`<button class="chip ${state.category===c?'active':''}" data-cat="${escapeHtml(c)}">${escapeHtml(c)}</button>`).join('');$$('[data-cat]').forEach(b=>b.onclick=()=>{state.category=b.dataset.cat;renderSimpleCatalog()});let items=db.filter(x=>(state.category==='全部'||x.cat===state.category)&&(!state.search||catalogSearchText(x).includes(state.search.toLowerCase())));$('#cards').innerHTML=items.length?items.map(x=>{const key=catalogKey(x),sel=['must','any','exclude'].some(m=>state[m].some(c=>c.key===key));const variable=hasCatalogVariables(x);return `<div class="card ${sel?'selected':''}" data-simple="${escapeHtml(x.id)}"><div class="card-top"><span class="icon">${escapeHtml(x.icon||'·')}</span><span class="tag">${escapeHtml(x.cat)}</span></div><div class="card-title">${escapeHtml(currentLabel(x))}</div><div class="card-text">${x.advanced?'原始正则片段':variable?'可填写数值':'固定文字匹配'}</div></div>`}).join(''):'<div class="empty">没有匹配词条</div>';$$('[data-simple]').forEach(n=>n.onclick=()=>{const x=db.find(v=>v.id===n.dataset.simple);if(x)addCatalogCondition(x)});$('#modsView').classList.remove('hidden');$('#uniquesView').classList.add('hidden');$('#basesView').classList.add('hidden')}
function renderTabletCatalog(){const views={mods:'#modsView',uniques:'#uniquesView',bases:'#basesView'};Object.entries(views).forEach(([v,id])=>$(id).classList.toggle('hidden',state.tabletView!==v));$$('#tabletViews button').forEach(b=>b.classList.toggle('active',b.dataset.view===state.tabletView));if(state.tabletView==='mods')renderTabletMods();if(state.tabletView==='uniques')renderUniques();if(state.tabletView==='bases')renderBases()}
function renderTabletMods(){const cats=['全部',...new Set(TABLET_DB.mods.map(x=>x.cat))];$('#chips').innerHTML=cats.map(c=>`<button class="chip ${state.category===c?'active':''}" data-cat="${escapeHtml(c)}">${escapeHtml(c)}</button>`).join('');$$('[data-cat]').forEach(b=>b.onclick=()=>{state.category=b.dataset.cat;renderTabletMods()});let xs=TABLET_DB.mods.filter(x=>(state.category==='全部'||x.cat===state.category)&&(state.affix==='全部词缀'||x.affix===state.affix)&&(!state.search||x.text.includes(state.search)));if(state.sort==='cat')xs.sort((a,b)=>a.cat.localeCompare(b.cat,'zh')||a.id.localeCompare(b.id));$('#cards').innerHTML=xs.length?xs.map(x=>{const parsed=parseTemplate(x),ranges=parsed.vars.map(v=>v.sourceMin==null?`${v.label||v.key}: 任意整数`:`${v.label||v.key}: ${v.sourceMin}–${v.sourceMax}`).join(' · '),key=`tablet:mod:${x.id}`,sel=['must','any','exclude'].some(m=>state[m].some(c=>c.key===key));return `<div class="card ${sel?'selected':''}" data-tmod="${x.id}"><div class="card-top"><span class="tag ${x.affix==='前缀'?'prefix':'suffix'}">${x.affix}</span><span class="tag">${escapeHtml(x.cat)}</span></div><div class="card-title">${escapeHtml(x.text.split('\n')[0])}</div>${x.text.includes('\n')?`<div class="card-text">${escapeHtml(x.text)}</div>`:''}${ranges?`<div class="range">${escapeHtml(ranges)}</div>`:''}</div>`}).join(''):'<div class="empty">没有匹配词条</div>';$$('[data-tmod]').forEach(n=>n.onclick=()=>addTablet(TABLET_DB.mods.find(x=>x.id===n.dataset.tmod),'mod'))}
function renderUniques(){$('#chips').innerHTML='';let xs=TABLET_DB.uniques.filter(u=>!state.search||u.name.includes(state.search)||u.base.includes(state.search)||u.attrs.some(a=>a.includes(state.search)));$('#uniqueGrid').innerHTML=xs.map(u=>`<div class="unique"><h3>${escapeHtml(u.name)}</h3><small>${escapeHtml(u.base)}</small><ul>${u.attrs.map(a=>`<li>${escapeHtml(a)}</li>`).join('')}</ul><div class="unique-actions"><button class="btn primary small" data-uname="${escapeHtml(u.name)}">按名称加入</button>${u.attrs.map((a,i)=>`<button class="btn small" data-uattr="${escapeHtml(u.name)}::${i}">属性 ${i+1}</button>`).join('')}</div></div>`).join('');$$('[data-uname]').forEach(b=>b.onclick=()=>addSimple(b.dataset.uname,flexText(b.dataset.uname),state.mode,`unique:${b.dataset.uname}`));$$('[data-uattr]').forEach(b=>b.onclick=()=>{const [name,iRaw]=b.dataset.uattr.split('::'),i=+iRaw,u=TABLET_DB.uniques.find(x=>x.name===name);const e={id:`unique-${name}-${i}`,text:u.attrs[i],affix:'传奇',cat:'传奇属性'};if(u.vars)e.vars=u.vars;addTablet(e,'uattr')})}
function renderBases(){const xs=TABLET_DB.bases.filter(b=>!state.search||b.name.includes(state.search)||b.implicit.includes(state.search));$('#chips').innerHTML='';$('#baseGrid').innerHTML=xs.map(b=>`<div class="unique"><h3>${escapeHtml(b.name)}</h3><small>${escapeHtml(b.implicit)} · 剩余次数：${b.uses}</small><div class="unique-actions"><button class="btn primary small" data-base="${escapeHtml(b.name)}">加入基底</button><button class="btn small" data-implicit="${escapeHtml(b.implicit)}">加入基底属性</button></div></div>`).join('');$$('[data-base]').forEach(b=>b.onclick=()=>addSimple(b.dataset.base,flexText(b.dataset.base),state.mode,`base:${b.dataset.base}`));$$('[data-implicit]').forEach(b=>b.onclick=()=>addSimple(b.dataset.implicit,flexText(b.dataset.implicit),state.mode,`implicit:${b.dataset.implicit}`))}
function renderConditions(){const names={must:'必须全部满足',any:'任意满足一项',exclude:'排除命中'};$('#conditionRoot').innerHTML=['must','any','exclude'].map(mode=>`<div class="condition-block"><div class="condition-title"><span>${names[mode]}</span><span class="count">${state[mode].length}</span></div>${state[mode].length?state[mode].map(c=>{const vars=c.kind==='tablet'?parseTemplate(c.entry).vars:[];return `<div class="condition"><div class="condition-head"><div class="condition-name">${escapeHtml(c.label)}</div><button class="x" data-remove="${mode}::${c.id}">×</button></div>${vars.map(v=>`<div class="var-grid"><label>${escapeHtml(v.label||v.key)}${v.sourceMin!=null?`（${v.sourceMin}–${v.sourceMax}）`:''}</label><input class="input" type="number" placeholder="最小" value="${escapeHtml(c.values[v.key]?.min??'')}" data-var="${mode}::${c.id}::${v.key}::min"><input class="input" type="number" placeholder="最大" value="${escapeHtml(c.values[v.key]?.max??'')}" data-var="${mode}::${c.id}::${v.key}::max"></div>`).join('')}</div>`}).join(''):'<div class="empty">暂无条件</div>'}</div>`).join('');$$('[data-remove]').forEach(b=>b.onclick=()=>{const [m,id]=b.dataset.remove.split('::');removeCondition(m,id)});$$('[data-var]').forEach(inp=>inp.oninput=()=>{const [m,id,key,side]=inp.dataset.var.split('::'),c=state[m].find(x=>x.id===id);c.values[key][side]=inp.value;renderOutput();scheduleWorkspaceSave()})}
function renderOutput(){const s=outputString();$('#output').textContent=s||'请选择词条';$('#length').textContent=`${s.length} / ${state.limit}`;const pct=Math.min(100,s.length/state.limit*100),m=$('#meter');m.querySelector('i').style.width=pct+'%';m.className='meter '+(s.length>state.limit?'bad':s.length>state.limit*.72?'warn':'')}
function renderStats(){$('#dbVersion').textContent=TABLET_DB.version;$('#dbStats').innerHTML=`<div class="hit"><b>${TABLET_DB.mods.length}</b> 条普通词缀（${TABLET_DB.mods.filter(x=>x.affix==='前缀').length} 前缀 / ${TABLET_DB.mods.filter(x=>x.affix==='后缀').length} 后缀）</div><div class="hit"><b>${TABLET_DB.uniques.length}</b> 件传奇石板</div><div class="hit"><b>${TABLET_DB.bases.length}</b> 种石板基底</div><div class="hit">数字支持句首、句中、句尾、多数字和括号范围</div>`}
function renderAll(){renderCatalog();renderConditions();renderOutput();renderStats();renderPresets();scheduleWorkspaceSave()}
function syncControls(){$$('#scopeList .scope').forEach(b=>b.classList.toggle('active',b.dataset.scope===state.scope));$$('#modeSwitch button').forEach(b=>b.classList.toggle('active',b.dataset.mode===state.mode));$('#locale').value=state.locale;$('#limit').value=state.limit}
function parseTabletText(text){const unique=TABLET_DB.uniques.find(u=>text.includes(u.name));const base=TABLET_DB.bases.find(b=>text.includes(b.name));const rarity=(text.match(/稀有度\s*[:：]\s*([^\n\r]+)/)||[])[1]?.trim()||'';const hits=[];for(const m of TABLET_DB.mods){try{if(new RegExp(tabletPattern({entry:m,values:{}},true),'m').test(text))hits.push(m)}catch{}}return{unique,base,rarity,hits}}
function showParsed(info){const rows=[];if(info.unique)rows.push(`<div class="hit">传奇：<b>${escapeHtml(info.unique.name)}</b> · ${escapeHtml(info.unique.base)}</div>`);if(info.base)rows.push(`<div class="hit">基底：<b>${escapeHtml(info.base.name)}</b></div>`);if(info.rarity)rows.push(`<div class="hit">稀有度：<b>${escapeHtml(info.rarity)}</b></div>`);for(const x of info.hits)rows.push(`<div class="hit">${x.affix} · ${escapeHtml(x.cat)}：${escapeHtml(x.text.split('\n')[0])}</div>`);$('#parserHits').innerHTML=rows.join('')||'<div class="empty">未识别到石板数据库词条</div>'}
function identifyTablet(add=true){const text=$('#itemText').value.trim();if(!text)return toast('请先粘贴物品文本');const info=parseTabletText(text);showParsed(info);if(add){state.scope='tablet';state.category='全部';syncControls();if(!state.must.some(c=>c.key==='class:tablet'))addSimple('物品类别: 石板','物品类别\\s*[:：]\\s*石板','must','class:tablet');if(info.unique)addSimple(info.unique.name,flexText(info.unique.name),'must',`unique:${info.unique.name}`);for(const m of info.hits)addTablet(m,'mod','must');toast(`识别到 ${info.hits.length} 条普通词缀${info.unique?'和传奇名称':''}`)}}
function runTest(){const text=$('#itemText').value,badge=$('#testResult');if(!text.trim()){badge.textContent='请先粘贴物品文本';badge.className='test-result fail';return}const rows=[];let pass=true;for(const c of state.must){const re=safeRegex(conditionPattern(c)),ok=!!re&&re.test(text);rows.push(`必须「${c.label}」${ok?'✓':'✗'}`);if(!ok)pass=false}if(state.any.length){const ok=state.any.some(c=>safeRegex(conditionPattern(c))?.test(text));rows.push(`任意组${ok?'✓':'✗'}`);if(!ok)pass=false}for(const c of state.exclude){const hit=safeRegex(conditionPattern(c))?.test(text);rows.push(`排除「${c.label}」${hit?'命中':'未命中'}`);if(hit)pass=false}badge.textContent=pass?'匹配成功':'未匹配';badge.className=`test-result ${pass?'pass':'fail'}`;$('#parserHits').innerHTML=rows.map(x=>`<div class="hit">${escapeHtml(x)}</div>`).join('')}
function numericPattern(){const label=$('#numberLabel').value.trim(),min=$('#numberMin').value,max=$('#numberMax').value;if(!label||(!min&&!max))return'';const n=`(?:${numberPattern(min,max)})`,t=flexText(label),pos=$('#numberPosition').value;return pos==='after'?`${t}[^\\n\\d-]{0,30}${n}(?:\\s*\\([^\\n)]*\\))?`:`${n}(?:\\s*\\([^\\n)]*\\))?[^\\n]{0,30}${t}`}
function updateNumberPreview(){const p=numericPattern();$('#numberPreview').textContent=p||'填写属性和数值后预览正则。'}
function compactLiteral(p){if(/[\\()|\[\]{}+*?^$]/.test(p))return p;const s=p.trim();if(/[\u4e00-\u9fff]/.test(s)&&s.length>7)return flexText(s.slice(-5));return p}
function compactAll(){pushHistory();let changed=0;for(const mode of ['must','any','exclude'])for(const c of state[mode])if(c.kind==='simple'&&!c.advanced){const n=compactLiteral(c.pattern);if(n.length<c.pattern.length){c.pattern=n;changed++}}renderAll();toast(changed?`已压缩 ${changed} 个条件`:'没有可安全压缩的条件')}
async function copyOutput(){const s=outputString();if(!s)return toast('当前没有正则');try{if(api?.copyText)await api.copyText(s);else if(navigator.clipboard)await navigator.clipboard.writeText(s);else{const t=document.createElement('textarea');t.value=s;document.body.appendChild(t);t.select();document.execCommand('copy');t.remove()}if(api?.recordRegexResult)api.recordRegexResult({query:s,scope:state.scope,limit:state.limit}).catch(()=>{});toast('正则已复制')}catch{toast('复制失败，请手动复制')}}
const quick=[
{name:'生命 + 任意元素抗性',scope:'equipment',build:()=>{addSimple('最大生命',flexText('最大生命'),'must','q:life');['火焰抗性','冰霜抗性','闪电抗性'].forEach(x=>addSimple(x,flexText(x),'any','q:'+x))}},
{name:'安全引路石',scope:'waystone',build:()=>['无法回复','反射伤害','恢复率降低','玩家受到诅咒'].forEach(x=>addSimple(x,flexText(x),'exclude','q:safe:'+x))},
{name:'石板：引路石收益',scope:'tablet',build:()=>['s03','s53'].forEach(id=>addTablet(TABLET_DB.mods.find(x=>x.id===id),'mod','any'))},
{name:'石板：迷雾收益',scope:'tablet',build:()=>['s57','s58','s59','s60'].forEach(id=>addTablet(TABLET_DB.mods.find(x=>x.id===id),'mod','any'))},
{name:'全部传奇石板',scope:'tablet',build:()=>TABLET_DB.uniques.forEach(u=>addSimple(u.name,flexText(u.name),'any',`unique:${u.name}`))}
];
function workspacePayload(){return{schemaVersion:2,scope:state.scope,locale:state.locale,mode:state.mode,category:state.category,affix:state.affix,sort:state.sort,tabletView:state.tabletView,must:clone(state.must),any:clone(state.any),exclude:clone(state.exclude),limit:state.limit}}
function scheduleWorkspaceSave(){if(initializing)return;clearTimeout(workspaceSaveTimer);workspaceSaveTimer=setTimeout(async()=>{const payload=workspacePayload();try{if(api?.saveRegexWorkspace)await api.saveRegexWorkspace(payload);else localStorage.setItem('poe2MergedRegexWorkspace',JSON.stringify(payload))}catch{}},260)}
function legacyRuleCondition(rule,mode,index){const raw=String(rule?.pattern||'').trim();if(!raw)return null;const literal=rule?.literal!==false;return{id:uid(),key:`legacy:${mode}:${index}:${raw}`,kind:'simple',label:raw,pattern:literal?flexText(raw):raw,advanced:!literal}}
function legacyNumericCondition(rule,index){const label=String(rule?.label||'').trim();if(!label)return null;const min=Number(rule?.min);if(!Number.isFinite(min))return null;const range=numberPattern(Math.max(0,Math.ceil(min)),999);return{id:uid(),key:`legacy:numeric:${index}:${label}:${min}`,kind:'simple',label:`${label} ≥ ${min}`,pattern:`${flexText(label)}[^\n\d-]{0,30}(?:(?:${range})|\d{4,})(?:\s*\([^\n)]*\))?`,advanced:true}}
function normalizePreset(p){const raw=p?.payload&&typeof p.payload==='object'&&!Array.isArray(p.payload)?{...p.payload,id:p.id,name:p.name||p.payload.name,description:p.description||p.payload.description,userDefined:p.userDefined}:p;if(raw?.format==='merged-regex-v2'||raw?.schemaVersion===2&&raw?.scope){return{...raw,scope:raw.scope||raw.category||'equipment',locale:raw.locale||'zh',tabletView:raw.tabletView||'mods',must:clone(raw.must||[]),any:clone(raw.any||[]),exclude:clone(raw.exclude||[]),limit:Number(raw.characterLimit||raw.limit)||250}}const must=(raw?.must||[]).map((x,i)=>legacyRuleCondition(x,'must',i)).filter(Boolean),any=(raw?.any||[]).map((x,i)=>legacyRuleCondition(x,'any',i)).filter(Boolean),exclude=(raw?.exclude||[]).map((x,i)=>legacyRuleCondition(x,'exclude',i)).filter(Boolean);for(const [i,x] of (raw?.numeric||[]).entries()){const c=legacyNumericCondition(x,i);if(!c)continue;(x.group==='any'?any:must).push(c)}return{...raw,scope:raw?.category==='map'?'waystone':raw?.category||'equipment',locale:'zh',tabletView:'mods',must,any,exclude,limit:Number(raw?.characterLimit)||250}}
function userPresets(){return presetCache.filter(p=>p.userDefined).map(normalizePreset)}
function builtInPresets(){return presetCache.filter(p=>!p.userDefined).map(normalizePreset)}
function applyPreset(p){pushHistory();state.scope=p.scope||'equipment';state.locale=p.locale||'zh';state.tabletView=p.tabletView||'mods';state.must=clone(p.must||[]);state.any=clone(p.any||[]);state.exclude=clone(p.exclude||[]);state.limit=Number(p.limit||p.characterLimit)||250;state.category='全部';syncControls();renderAll();toast(`已载入：${p.name}`)}
function renderPresets(){const built=builtInPresets();$('#quickPresets').innerHTML=quick.map((p,i)=>`<button class="preset" data-quick="${i}">${escapeHtml(p.name)}<small>${p.scope}</small></button>`).join('')+built.map((p,i)=>`<button class="preset" data-built="${i}">${escapeHtml(p.name)}<small>桌面助手内置</small></button>`).join('');$$('[data-quick]').forEach(b=>b.onclick=()=>{const p=quick[+b.dataset.quick];state.scope=p.scope;state.category='全部';syncControls();renderCatalog();p.build();toast('已载入模板')});$$('[data-built]').forEach(b=>b.onclick=()=>applyPreset(built[+b.dataset.built]));const users=userPresets();$('#userPresets').innerHTML=users.length?users.map((p,i)=>`<div class="preset-row"><button class="preset" data-user="${i}">${escapeHtml(p.name)}<small>${(p.must?.length||0)+(p.any?.length||0)+(p.exclude?.length||0)} 条件 · ${escapeHtml(p.scope||'equipment')}</small></button><button class="btn danger small" data-delete-preset="${escapeHtml(p.id||'')}">删除</button></div>`).join(''):'<div class="panel-sub">暂无自建预设</div>';$$('[data-user]').forEach(b=>b.onclick=()=>applyPreset(users[+b.dataset.user]));$$('[data-delete-preset]').forEach(b=>b.onclick=async()=>{if(!b.dataset.deletePreset)return;try{if(api?.deleteRegexPreset)await api.deleteRegexPreset(b.dataset.deletePreset);presetCache=presetCache.filter(x=>x.id!==b.dataset.deletePreset);renderPresets();toast('预设已删除')}catch{toast('删除预设失败')}})}
async function savePreset(){const name=$('#presetName').value.trim();if(!name)return toast('请输入预设名称');const old=userPresets().find(x=>x.name===name);const payload={id:old?.id,name,format:'merged-regex-v2',schemaVersion:2,scope:state.scope,category:state.scope,locale:state.locale,tabletView:state.tabletView,must:clone(state.must),any:clone(state.any),exclude:clone(state.exclude),numeric:[],characterLimit:state.limit};try{if(api?.saveRegexPreset){const result=await api.saveRegexPreset(payload);presetCache=[{...result.preset,userDefined:true},...presetCache.filter(x=>x.id!==result.preset.id)]}else{const list=userPresets().filter(x=>x.name!==name);list.unshift({...payload,id:old?.id||`user-local-${Date.now()}`,userDefined:true});localStorage.setItem('poe2MergedRegexPresets',JSON.stringify(list));presetCache=list}$('#presetName').value='';renderPresets();toast('预设已保存')}catch{toast('保存预设失败')}}
function exportPresets(){const blob=new Blob([JSON.stringify({schemaVersion:2,exportedAt:new Date().toISOString(),presets:userPresets().map(p=>({...p,userDefined:undefined}))},null,2)],{type:'application/json'}),url=URL.createObjectURL(blob),a=document.createElement('a');a.href=url;a.download='poe2-regex-presets-v2.json';a.click();URL.revokeObjectURL(url)}
function importPresets(file){const r=new FileReader();r.onload=async()=>{try{const d=JSON.parse(r.result),items=Array.isArray(d)?d:d.presets;if(!Array.isArray(items))throw new Error('bad');let count=0;for(const raw of items){const p=normalizePreset(raw);const payload={...p,id:String(p.id||'').startsWith('user-')?p.id:undefined,name:p.name||`导入预设 ${count+1}`,format:'merged-regex-v2',schemaVersion:2,category:p.scope,characterLimit:p.limit||250};if(api?.saveRegexPreset){const result=await api.saveRegexPreset(payload);presetCache=[{...result.preset,userDefined:true},...presetCache.filter(x=>x.id!==result.preset.id)]}else presetCache.push({...payload,id:`user-local-${Date.now()}-${count}`,userDefined:true});count++}if(!api)localStorage.setItem('poe2MergedRegexPresets',JSON.stringify(userPresets()));renderPresets();toast(`已导入 ${count} 个预设`)}catch{toast('导入失败：格式错误')}};r.readAsText(file,'utf-8')}
async function loadDesktopIntegration(){try{if(api?.listRegexPresets){const result=await api.listRegexPresets();presetCache=Array.isArray(result?.presets)?result.presets:[]}else{const local=JSON.parse(localStorage.getItem('poe2MergedRegexPresets')||'[]');presetCache=local.map(x=>({...x,userDefined:true}))}let saved=null;if(api?.getRegexWorkspace)saved=(await api.getRegexWorkspace())?.workspace;else saved=JSON.parse(localStorage.getItem('poe2MergedRegexWorkspace')||'null');if(saved){const p=normalizePreset({...saved,format:'merged-regex-v2'});state.scope=p.scope;state.locale=p.locale;state.mode=['must','any','exclude'].includes(saved.mode)?saved.mode:'must';state.category=saved.category||'全部';state.affix=saved.affix||'全部词缀';state.sort=saved.sort||'source';state.tabletView=p.tabletView;state.must=p.must;state.any=p.any;state.exclude=p.exclude;state.limit=p.limit}}catch{}finally{initializing=false;syncControls();renderAll()}}
$$('#scopeList .scope').forEach(b=>b.onclick=()=>{state.scope=b.dataset.scope;state.category='全部';state.search='';$('#search').value='';syncControls();renderCatalog();scheduleWorkspaceSave()});$$('#modeSwitch button').forEach(b=>b.onclick=()=>{state.mode=b.dataset.mode;syncControls();scheduleWorkspaceSave()});$$('#tabletViews button').forEach(b=>b.onclick=()=>{state.tabletView=b.dataset.view;state.category='全部';renderTabletCatalog();scheduleWorkspaceSave()});$('#search').oninput=e=>{state.search=e.target.value.trim();renderCatalog()};$('#affixFilter').onchange=e=>{state.affix=e.target.value;renderTabletMods()};$('#sort').onchange=e=>{state.sort=e.target.value;renderTabletMods()};$('#locale').onchange=e=>{state.locale=e.target.value;renderCatalog();scheduleWorkspaceSave()};$('#limit').onchange=e=>{state.limit=+e.target.value;renderOutput();scheduleWorkspaceSave()};$('#addCustomBtn').onclick=()=>{const raw=$('#customInput').value.trim();if(!raw)return;const adv=$('#advancedToggle').checked;addSimple(raw,adv?raw:flexText(raw),state.mode,`custom:${raw}:${adv}`,adv);$('#customInput').value=''};$('#customInput').onkeydown=e=>{if(e.key==='Enter')$('#addCustomBtn').click()};['numberLabel','numberMin','numberMax'].forEach(id=>$('#'+id).oninput=updateNumberPreview);$('#numberPosition').onchange=updateNumberPreview;$('#addNumberBtn').onclick=()=>{const p=numericPattern();if(!p)return toast('请填写属性和数值');addSimple($('#numberLabel').value.trim(),p,$('#numberType').value,`numeric:${p}`,true)};$('#clearBtn').onclick=()=>{pushHistory();state.must=[];state.any=[];state.exclude=[];renderAll()};$('#undoBtn').onclick=undo;$('#copyBtn').onclick=copyOutput;$('#copyTopBtn').onclick=copyOutput;$('#compactBtn').onclick=compactAll;$('#readClipboardBtn').onclick=async()=>{try{const result=api?.readClipboardText?await api.readClipboardText():{text:await navigator.clipboard.readText()};$('#itemText').value=result?.text||'';showParsed(parseTabletText($('#itemText').value));toast(result?.text?'已读取剪贴板':'剪贴板为空')}catch{toast('读取剪贴板失败')}};$('#testBtn').onclick=runTest;$('#identifyBtn').onclick=()=>identifyTablet(true);$('#addBaseBtn').onclick=()=>{const info=parseTabletText($('#itemText').value);showParsed(info);if(info.base)addSimple(info.base.name,flexText(info.base.name),'must',`base:${info.base.name}`);else toast('未识别到石板基底')};$('#addRarityBtn').onclick=()=>{const info=parseTabletText($('#itemText').value);showParsed(info);if(info.rarity)addSimple(`稀有度: ${info.rarity}`,`稀有度\\s*[:：]\\s*${flexText(info.rarity)}`,'must',`rarity:${info.rarity}`);else toast('未识别到稀有度')};$('#sampleBtn').onclick=()=>{$('#itemText').value=`物品类别: 石板\n稀有度: 魔法\n制图师之 霸主石板\n--------\n物品等级: 82\n--------\n{ 基底属性 }\n强化一张地图中的地图首领\n剩余次数：10\n--------\n{ 后缀属性 "制图师之" (等阶：1) }\n地图内找到的引路石数量提高 31 (30-40)%\n--------\n可以在私人地图装置中使用，为地图添加词缀。\n--------\n引路石掉落`;showParsed(parseTabletText($('#itemText').value))};$('#savePresetBtn').onclick=savePreset;$('#exportBtn').onclick=exportPresets;$('#importBtn').onclick=()=>$('#importFile').click();$('#importFile').onchange=e=>{const f=e.target.files?.[0];if(f)importPresets(f);e.target.value=''};
syncControls();renderAll();updateNumberPreview();loadDesktopIntegration();
